import play.api.libs.json._
import javax.inject.Inject
import com.example.database.OrdersRepository

class OrdersController @Inject()(ordersRepository: OrdersRepository) extends Controller {
    def getOrderById(id: Long): Action[AnyContent] = Action { implicit request =>
